using Newtonsoft.Json.Linq;
using System.Reflection;
using System.Runtime.CompilerServices;
using System.Runtime.InteropServices;
using TerbinLibrary;
using TerbinLibrary.Communication;
using TerbinLibrary.Configuration;
using TerbinLibrary.Execution;
using TerbinLibrary.Serialize;
using TerbinLibrary.SteamFarlands;




var communicator = new TerbinCommunicator(false);
TerbinExecutor.Register(Assembly.GetExecutingAssembly());
communicator.OnRecive += TerbinExecutableManager.DispatchAsync;

if (await communicator.Connect())
{
    Console.WriteLine($"[Client] ¡Conectado!");
}
else
{
    Console.WriteLine($"[Client] ¡Error de Conexion!");
    return;
}


//ExecutableDispatcher.RegisterFromAssembly(Assembly.GetExecutingAssembly());
//TerbinExecutableCRUDManager.RegisterFromAssembly(Assembly.GetExecutingAssembly());

while (true)
{
    Console.Write($"-------( Start )---------\n" +
        $"[Client] (byte de accion: 0 = Stop, 10 = CreateInstance, )\n" +
        $"[Client] Action -> ");
    byte input = byte.Parse(Console.ReadLine()); // alacguabar!
    byte input2 = byte.MaxValue;

    if (input >= (byte)CodeTerbinProtocol.Create &&
        input <= (byte)CodeTerbinProtocol.Deleted)
    {
        Console.Write($"[Client] Action2 ->");
        input2 = byte.Parse(Console.ReadLine()); // alacguabar!
    }
    Console.Write($"[Client] ({input}), {(CodeMethodsTerbinService)input}\n" +
        $"-------(  End  )---------\n");

    //char[] dirFarlands = ManagerFarlands.GetRuteSteamFarlands()?.ToCharArray() ?? "matenme".ToCharArray();
    char[] pruebaEspacio = "".ToCharArray();
    //char[] pruebaEspacio = "ABCDEF".ToCharArray();

    // Esto fufa :)
    byte[] menssaje;
    if (input2 != byte.MaxValue)
    {
        // Incluye input2 al inicio del mensaje
        int size = (Serialineitor.GetArraySize<char>(pruebaEspacio.Length + TerbinConfiguration.RUTE_FARLANDS.ToCharArray().Length)) + 8;

        menssaje = new byte[size];
        Span<byte> m = menssaje;

        BufferErrorCode er;
        er = m.Write<byte>(input2);
        if (er != BufferErrorCode.Succes) Console.WriteLine($"1Error: {er}");
        er = m.WriteArray<char>(TerbinConfiguration.RUTE_FARLANDS.ToCharArray());
        if (er != BufferErrorCode.Succes) Console.WriteLine($"2Error: {er}");
        er = m.WriteArray<char>(pruebaEspacio);
        if (er != BufferErrorCode.Succes) Console.WriteLine($"3Error: {er}");

        Console.WriteLine($"-- Prueba Espacio mide: {pruebaEspacio.Length}");

        //var keyMsg = Serialineitor.SerializeArray<char>(TerbinConfiguration.RUTE_FARLANDS.ToCharArray());
        //var baseMsg = Serialineitor.SerializeArray<char>("matenme".ToCharArray());
        //menssaje = new byte[keyMsg.Length + baseMsg.Length + 1];
        //menssaje[0] = input2;
        //Array.Copy(keyMsg, 0, menssaje, 1, keyMsg.Length);
        //Array.Copy(baseMsg, 0, menssaje, keyMsg.Length, baseMsg.Length);
    }
    else
    {
        menssaje = Serialineitor.SerializeArray<char>("matenme".ToCharArray());
    }


    //char[] m = "matenme".ToCharArray();

    // TODO: (Solucionar error):  Este solo manda 12 bytes.
    Span<byte> spanMenssaje = new byte["matenme".ToCharArray().Length * 2];
    spanMenssaje.WriteArray<char>("matenme".ToCharArray());

    // TODO: (Solucionar error): Este solo manda 7 bytes.
    MemoryStream memo = new MemoryStream();
    StreamWriter writer = new StreamWriter(memo);

    writer.Write("matenme".ToCharArray());
    writer.Flush();

    var a = spanMenssaje.ToArray();

    //Console.WriteLine($"[Client] Mensaje: {spanMenssaje.ToArray().ToString()}");
    try
    {
        Console.WriteLine($"[Client] M (l:{menssaje.Length})");
        var r = await communicator.Communicate(input, menssaje);
        Console.WriteLine($"[Client] R (Action: {r.ActionMethod} | Status: {r.Head.Status} | Memory: {r.Head.IdMemory})");
        if (r.Payload.Length > 0)
        {
            string rute = new(Serialineitor.DeserializeArray<char>(r.Payload));
            Console.WriteLine($"[Client] R (l: {rute.Length}, m: {rute})");
        }
        else
        {
            Console.WriteLine($"[Client] R (PLD_l: {r.Payload.Length})");
        }

        if (r.Head.Status == CodeStatus.Succes && input == 0)
        {
            Console.WriteLine($"[Client] Desconexion elegida, esperando confirmación del servidor...");
            break; // <-- Ahora sí, nos largamos!.
        }
    }
    catch (Exception e)
    {
        Console.WriteLine($"[Client] Error-> {e.Message}");
    }
}

